#include<bits/stdc++.h>
using namespace std;

long long  c[2005][2005], mi2[2005];
long long t, mod = 1000000007;
void init() {
	c[0][0] = 1;
	c[1][0] = 1;
	c[1][1] = 1;
	for (int i = 2; i <= 2003; i++) {
		c[i][0] = 1;
		for (int j = 1; j <= i; j++) {
			c[i][j] = (c[i - 1][j - 1] + c[i - 1][j]) % mod;
		}
	}
	mi2[0] = 1;
	for (int i = 1; i <= 2000; i++) {
		mi2[i] = mi2[i - 1] * 2 % mod;
	}
}
void solve() {
	int n, m, k;
	cin >> n >> m >> k;
	if (m - 2 * k < 0 || m - 2 * k > n - k) {
		cout << 0 <<"\n";
		return;
	}

	cout << (c[n][k] * mi2[m - 2 * k] % mod ) * c[n - k][m - 2 * k] % mod << '\n';
}
int main() {
	init();
	cin >> t;
	while (t--) {
		solve();
	}
}
